{"purpose":"S03 notification contract source scan","runtime":"python3","script":"from pathlib import Path
files = [
'backend/src/services/dailyBriefService.ts','backend/src/services/deepDiveService.ts','backend/src/services/fullReportService.ts','backend/src/services/quickCheckService.ts','backend/src/services/newIdeasService.ts','backend/src/services/feedService.ts','backend/src/services/stepQueue/completionEffects.ts','backend/src/services/notificationService.ts','backend/src/services/telegramDelivery.ts','backend/src/routes/telegram.ts']
legacy=[]
for f in files:
    text=Path(f).read_text()
    if 'parse_mode' in text or 'parseMode:' in text:
        legacy.append((f,'parse_mode/parseMode present'))
    if 'publishNotification({' in text and 'kind:' not in text and f!='backend/src/services/notificationService.ts':
        legacy.append((f,'publishNotification call without semantic kind marker'))
print('scanned_files=', len(files))
print('issues=', legacy if legacy else 'none')
for f in ['backend/src/services/telegramDelivery.ts','backend/src/services/notificationService.ts']:
    text=Path(f).read_text()
    signals=[s for s in ['disable_web_page_preview','MAX_TELEGRAM_MESSAGE_LENGTH','deliveryError','deliveredAt','console.info','console.warn'] if s in text]
    print(f, 'signals:', ', '.join(signals))","timeout_ms":120000}

{
  "milestoneId": "M001",
